1	const cellKey = (x: number, y: number): string => `${x},${y}`;
2	
3	const parseKey = (key: string): number[] => key.split(",").map(Number);
4	
5	const NEIGHBOR_OFFSETS: number[][] = [
6	  [-1, -1], [0, -1], [1, -1],
7	  [-1,  0],          [1,  0],
8	  [-1,  1], [0,  1], [1,  1],
9	];
10	
11	const neighborKeys = (x: number, y: number): string[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => cellKey(x + dx, y + dy));
13	
14	export const nextGeneration = (liveCells: number[][]): number[][] => {
15	  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
16	
17	  const neighborCounts = new Map<string, number>();
18	
19	  for (const [x, y] of liveCells) {
20	    for (const key of neighborKeys(x, y)) {
21	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
22	    }
23	  }
24	
25	  const nextLiveCells: number[][] = [];
26	
27	  for (const [key, count] of neighborCounts) {
28	    if (count === 3 || (count === 2 && liveSet.has(key))) {
29	      nextLiveCells.push(parseKey(key));
30	    }
31	  }
32	
33	  return nextLiveCells;
34	};
